  1→/**
  2→ * CLI Proxy Setup Acceptance Test Kit
  3→ *
  4→ * Domain-specific helpers for proxy token and CLI proxy setup tests.
  5→ * Extends the shared acceptance-test-kit and llm-proxy-test-kit with
  6→ * proxy token issuance, validation, and CLI config helpers.
  7→ *
  8→ * Driving ports:
  9→ *   - POST /api/auth/proxy-token (issue proxy tokens)
 10→ *   - POST /proxy/llm/anthropic/v1/messages (proxy with Brain auth)
 11→ *   - CLI config files (~/.brain/config.json, .claude/settings.local.json)
 12→ */
 13→import { RecordId, type Surreal } from "surrealdb";
 14→import {
 15→  setupAcceptanceSuite,
 16→  createTestUser,
 17→  fetchRaw,
 18→  type AcceptanceTestRuntime,
 19→  type TestUser,
 20→} from "../acceptance-test-kit";
 21→import {
 22→  createProxyTestWorkspace,
 23→  buildProxyRequestBody,
 24→} from "../llm-proxy/llm-proxy-test-kit";
 25→
 26→// Re-export shared helpers
 27→export {
 28→  setupAcceptanceSuite,
 29→  createTestUser,
 30→  fetchRaw,
 31→  createProxyTestWorkspace,
 32→  type AcceptanceTestRuntime,
 33→  type TestUser,
 34→};
 35→
 36→export type { ProxyTestUser };
 37→
 38→// ---------------------------------------------------------------------------
 39→// Proxy Token Issuance Helpers
 40→// ---------------------------------------------------------------------------
 41→
 42→export type ProxyTokenResponse = {
 43→  proxy_token: string;
 44→  expires_at: string;
 45→  workspace_id: string;
 46→};
 47→
 48→/**
 49→ * Request a proxy token from the server, simulating what `brain init` Step 7 does.
 50→ *
 51→ * The endpoint validates via Better Auth session cookies (not the Bearer value).
 52→ * Pass sessionHeaders from createProxyTestUser() which contains Cookie header.
 53→ * A dummy Authorization: Bearer header is included to satisfy the parse check.
 54→ */
 55→export async function requestProxyToken(
 56→  baseUrl: string,
 57→  sessionHeaders: Record<string, string>,
 58→  workspaceId: string,
 59→): Promise<Response> {
 60→  return fetch(`${baseUrl}/api/auth/proxy-token`, {
 61→    method: "POST",
 62→    headers: {
 63→      "Content-Type": "application/json",
 64→      "Authorization": "Bearer session-via-cookie",
 65→      ...sessionHeaders,
 66→    },
 67→    body: JSON.stringify({ workspace_id: workspaceId }),
 68→  });
 69→}
 70→
 71→// ---------------------------------------------------------------------------
 72→// Full Proxy Test User Setup
 73→// ---------------------------------------------------------------------------
 74→
 75→export type ProxyTestUser = {
 76→  sessionHeaders: Record<string, string>;
 77→  workspaceId: string;
 78→  identityId: string;
 79→  personId: string;
 80→};
 81→
 82→/**
 83→ * Create a fully-wired test user for proxy token tests.
 84→ *
 85→ * Pipeline:
 86→ *   1. Sign up via Better Auth → session cookies + person ID
 87→ *   2. Create workspace
 88→ *   3. Create identity with identity_person edge (person → identity)
 89→ *   4. Create member_of edge (identity → workspace)
 90→ *
 91→ * Returns session headers (cookies) for use with requestProxyToken().
 92→ */
 93→export async function createProxyTestUser(
 94→  baseUrl: string,
 95→  surreal: Surreal,
 96→  suffix: string,
 97→): Promise<ProxyTestUser> {
 98→  const workspaceId = `ws-${suffix}-${crypto.randomUUID()}`;
 99→  const identityId = `id-${suffix}-${crypto.randomUUID()}`;
100→
101→  // 1. Create real Better Auth user → session cookies
102→  const email = `proxy-${Date.now()}-${suffix}@test.local`;
103→  const signUpResponse = await fetch(`${baseUrl}/api/auth/sign-up/email`, {
104→    method: "POST",
105→    headers: { "Content-Type": "application/json" },
106→    body: JSON.stringify({ name: "Proxy Test User", email, password: "test-password-123" }),
107→    redirect: "manual",
108→  });
109→
110→  if (!signUpResponse.ok) {
111→    const body = await signUpResponse.text();
112→    throw new Error(`Failed to create proxy test user (${signUpResponse.status}): ${body}`);
113→  }
114→
115→  const setCookie = signUpResponse.headers.getSetCookie();
116→  if (!setCookie || setCookie.length === 0) {
117→    throw new Error("Sign-up did not return session cookies");
118→  }
119→
120→  const cookieHeader = setCookie.map((c) => c.split(";")[0]).join("; ");
121→  const sessionHeaders: Record<string, string> = { Cookie: cookieHeader };
122→
123→  // Extract person ID from sign-up response body
124→  const signUpBody = await signUpResponse.json() as { user?: { id?: string } };
125→  const personId = signUpBody.user?.id;
126→  if (!personId) {
127→    throw new Error("Sign-up response did not include user ID");
128→  }
129→
130→  // 2. Create workspace
131→  await createProxyTestWorkspace(surreal, workspaceId);
132→
133→  // 3. Create identity
134→  const identityRecord = new RecordId("identity", identityId);
135→  const workspaceRec = new RecordId("workspace", workspaceId);
136→  const personRecord = new RecordId("person", personId);
137→
138→  await surreal.query(`CREATE $identity CONTENT $content;`, {
139→    identity: identityRecord,
140→    content: {
141→      name: "Proxy Test User",
142→      type: "human",
143→      role: "owner",
144→      workspace: workspaceRec,
145→      created_at: new Date(),
146→    },
147→  });
148→
149→  // 4. Create identity_person edge (identity → person)
150→  await surreal.query(
151→    `RELATE $identity->identity_person->$person SET added_at = time::now();`,
152→    { identity: identityRecord, person: personRecord },
153→  );
154→
155→  // 5. Create member_of edge (identity → workspace)
156→  await surreal.query(
157→    `RELATE $identity->member_of->$workspace SET role = "admin", added_at = time::now();`,
158→    { identity: identityRecord, workspace: workspaceRec },
159→  );
160→
161→  return { sessionHeaders, workspaceId, identityId, personId };
162→}
163→
164→// ---------------------------------------------------------------------------
165→// Brain-Auth Proxy Request Helpers
166→// ---------------------------------------------------------------------------
167→
168→/**
169→ * Send a proxy request using Brain auth (X-Brain-Auth header) instead of
170→ * direct Anthropic API key. This is how Claude Code routes through the proxy
171→ * after `brain init` configures settings.local.json.
172→ */
173→export async function sendBrainAuthProxyRequest(
174→  baseUrl: string,
175→  proxyToken: string,
176→  options?: {
177→    model?: string;
178→    maxTokens?: number;
179→    messages?: Array<{ role: string; content: string }>;
180→    stream?: boolean;
181→  },
182→): Promise<Response> {
183→  const body = buildProxyRequestBody({
184→    model: options?.model ?? "claude-sonnet-4-20250514",
185→    maxTokens: options?.maxTokens ?? 20,
186→    messages: options?.messages ?? [{ role: "user", content: "Say exactly: test" }],
187→    stream: options?.stream ?? false,
188→  });
189→
190→  return fetch(`${baseUrl}/proxy/llm/anthropic/v1/messages`, {
191→    method: "POST",
192→    headers: {
193→      "Content-Type": "application/json",
194→      "anthropic-version": "2023-06-01",
195→      "X-Brain-Auth": proxyToken,
196→    },
197→    body,
198→  });
199→}
200→
201→// ---------------------------------------------------------------------------
202→// Proxy Token DB Helpers
203→// ---------------------------------------------------------------------------
204→
205→export type ProxyTokenRecord = {
206→  id: RecordId;
207→  token_hash: string;
208→  workspace: RecordId;
209→  identity: RecordId;
210→  expires_at: Date;
211→  created_at: Date;
212→  revoked: boolean;
213→};
214→
215→/**
216→ * Query all proxy tokens for an identity+workspace pair.
217→ */
218→export async function getProxyTokensForIdentity(
219→  surreal: Surreal,
220→  identityId: string,
221→  workspaceId: string,
222→): Promise<ProxyTokenRecord[]> {
223→  const identityRecord = new RecordId("identity", identityId);
224→  const workspaceRecord = new RecordId("workspace", workspaceId);
225→
226→  const results = await surreal.query(
227→    `SELECT * FROM proxy_token WHERE identity = $identity AND workspace = $ws ORDER BY created_at DESC;`,
228→    { identity: identityRecord, ws: workspaceRecord },
229→  );
230→
231→  return (results[0] ?? []) as ProxyTokenRecord[];
232→}
233→
234→/**
235→ * Count active (non-revoked, non-expired) proxy tokens for an identity+workspace.
236→ */
237→export async function countActiveProxyTokens(
238→  surreal: Surreal,
239→  identityId: string,
240→  workspaceId: string,
241→): Promise<number> {
242→  const identityRecord = new RecordId("identity", identityId);
243→  const workspaceRecord = new RecordId("workspace", workspaceId);
244→
245→  const results = await surreal.query(
246→    `SELECT count() AS total FROM proxy_token WHERE identity = $identity AND workspace = $ws AND revoked = false AND expires_at > time::now() GROUP ALL;`,
247→    { identity: identityRecord, ws: workspaceRecord },
248→  );
249→
250→  const rows = (results[0] ?? []) as Array<{ total: number }>;
251→  return rows[0]?.total ?? 0;
252→}
253→
254→/**
255→ * Seed an expired proxy token for testing expiry detection scenarios.
256→ */
257→export async function seedExpiredProxyToken(
258→  surreal: Surreal,
259→  tokenId: string,
260→  options: {
261→    tokenHash: string;
262→    workspaceId: string;
263→    identityId: string;
264→    expiredDaysAgo?: number;
265→  },
266→): Promise<string> {
267→  const tokenRecord = new RecordId("proxy_token", tokenId);
268→  const workspaceRecord = new RecordId("workspace", options.workspaceId);
269→  const identityRecord = new RecordId("identity", options.identityId);
270→  const daysAgo = options.expiredDaysAgo ?? 1;
271→  const expiredAt = new Date(Date.now() - daysAgo * 24 * 60 * 60 * 1000);
272→
273→  await surreal.query(`CREATE $tkn CONTENT $content;`, {
274→    tkn: tokenRecord,
275→    content: {
276→      token_hash: options.tokenHash,
277→      workspace: workspaceRecord,
278→      identity: identityRecord,
279→      expires_at: expiredAt,
280→      created_at: new Date(expiredAt.getTime() - 90 * 24 * 60 * 60 * 1000),
281→      revoked: false,
282→    },
283→  });
284→
285→  return tokenId;
286→}
287→
288→// ---------------------------------------------------------------------------
289→// CLI Config Simulation Helpers
290→// ---------------------------------------------------------------------------
291→
292→/**
293→ * Build what brain init Step 7 should write to .claude/settings.local.json.
294→ * Used for asserting CLI output correctness.
295→ */
296→export function buildExpectedSettingsLocal(
297→  serverUrl: string,
298→  proxyToken: string,
299→): Record<string, unknown> {
300→  return {
301→    env: {
302→      ANTHROPIC_BASE_URL: `${serverUrl}/proxy/llm/anthropic`,
303→      ANTHROPIC_CUSTOM_HEADERS: `X-Brain-Auth: ${proxyToken}`,
304→    },
305→  };
306→}
307→
308→/**
309→ * Build what brain init Step 7 should store in ~/.brain/config.json repo entry.
310→ */
311→export function buildExpectedRepoConfig(
312→  proxyToken: string,
313→  expiresAt: string,
314→): { proxy_token: string; proxy_token_expires_at: string } {
315→  return {
316→    proxy_token: proxyToken,
317→    proxy_token_expires_at: expiresAt,
318→  };
319→}
320→
321→// ---------------------------------------------------------------------------
322→// Identity + Workspace Setup (for OAuth simulation in tests)
323→// ---------------------------------------------------------------------------
324→
325→/**
326→ * Create a test identity and workspace with member_of edge,
327→ * and return a simulated access token for proxy token issuance tests.
328→ *
329→ * Note: In real flow, access_token comes from OAuth. In acceptance tests,
330→ * we either use the acceptance-test-kit's createTestUser or seed directly.
331→ */
332→export async function createProxyTestIdentity(
333→  surreal: Surreal,
334→  options: {
335→    identityId: string;
336→    workspaceId: string;
337→    email?: string;
338→  },
