  1→/**
  2→ * Proxy Token Route — POST /api/auth/proxy-token
  3→ *
  4→ * Issues brp_-prefixed proxy tokens for CLI authentication.
  5→ * Pipeline:
  6→ *   1. Parse workspace_id from request body + extract bearer token
  7→ *   2. Validate bearer token via Better Auth session
  8→ *   3. Resolve authenticated person → identity (scoped to workspace membership)
  9→ *   4. Revoke previous tokens + issue new one (atomic transaction)
 10→ *   5. Return raw token + expiry
 11→ *
 12→ * Driving port: POST /api/auth/proxy-token
 13→ * Driven ports: SurrealDB (proxy_token table)
 14→ */
 15→import { RecordId } from "surrealdb";
 16→import { jsonResponse } from "../http/response";
 17→import {
 18→  generateProxyToken,
 19→  hashProxyToken,
 20→  computeExpiresAt,
 21→  readProxyTokenTtlDays,
 22→} from "./proxy-token-core";
 23→import type { ServerDependencies } from "../runtime/types";
 24→import { log } from "../telemetry/logger";
 25→import { createJwtValidator } from "../mcp/token-validation";
 26→
 27→// ---------------------------------------------------------------------------
 28→// Request Parsing (pure)
 29→// ---------------------------------------------------------------------------
 30→
 31→type ProxyTokenRequest = {
 32→  workspaceId: string;
 33→  bearerToken: string;
 34→};
 35→
 36→function parseProxyTokenRequest(
 37→  authHeader: string | null,
 38→  body: unknown,
 39→): { ok: true; value: ProxyTokenRequest } | { ok: false; status: number; error: string } {
 40→  if (!authHeader || !authHeader.startsWith("Bearer ")) {
 41→    return { ok: false, status: 401, error: "missing_authorization" };
 42→  }
 43→
 44→  const bearerToken = authHeader.slice(7).trim();
 45→  if (!bearerToken) {
 46→    return { ok: false, status: 401, error: "missing_authorization" };
 47→  }
 48→
 49→  const parsed = body as { workspace_id?: string } | undefined;
 50→  if (!parsed?.workspace_id || typeof parsed.workspace_id !== "string") {
 51→    return { ok: false, status: 400, error: "workspace_id_required" };
 52→  }
 53→
 54→  return {
 55→    ok: true,
 56→    value: { workspaceId: parsed.workspace_id, bearerToken },
 57→  };
 58→}
 59→
 60→// ---------------------------------------------------------------------------
 61→// Identity Resolution (driven port — queries SurrealDB)
 62→// Resolves the identity for a person that is a member of the target workspace,
 63→// avoiding false 403s when a person has multiple identities.
 64→// ---------------------------------------------------------------------------
 65→
 66→async function resolveIdentityForWorkspaceAndPerson(
 67→  surreal: ServerDependencies["surreal"],
 68→  personId: string,
 69→  workspaceId: string,
 70→): Promise<string | undefined> {
 71→  const personRecord = new RecordId("person", personId);
 72→  const wsRecord = new RecordId("workspace", workspaceId);
 73→  const results = await surreal.query<[undefined, RecordId[]]>(
 74→    `LET $identities = SELECT VALUE in FROM identity_person WHERE out = $person;
 75→     SELECT VALUE id FROM identity WHERE id IN $identities AND id IN (SELECT VALUE in FROM member_of WHERE out = $ws) LIMIT 1;`,
 76→    { person: personRecord, ws: wsRecord },
 77→  );
 78→  const identityRec = results[1]?.[0];
 79→  return identityRec?.id as string | undefined;
 80→}
 81→
 82→// ---------------------------------------------------------------------------
 83→// Record ID Helpers
 84→// ---------------------------------------------------------------------------
 85→
 86→function identityRecord(identityId: string): RecordId {
 87→  return new RecordId("identity", identityId);
 88→}
 89→
 90→function workspaceRecord(workspaceId: string): RecordId {
 91→  return new RecordId("workspace", workspaceId);
 92→}
 93→
 94→// ---------------------------------------------------------------------------
 95→// Session Validation (driven port — Better Auth)
 96→// ---------------------------------------------------------------------------
 97→
 98→async function validateSession(
 99→  auth: ServerDependencies["auth"],
100→  headers: Headers,
101→  bearerToken: string,
102→  betterAuthUrl: string,
103→): Promise<string | undefined> {
104→  const session = await auth.api.getSession({ headers });
105→  if (session?.user?.id) {
106→    return session.user.id;
107→  }
108→
109→  // Fallback for CLI OAuth bearer tokens (no browser session cookie).
110→  // Accept both common audience variants:
111→  //  - <server base URL>
112→  //  - <server base URL>/api/auth
113→  const validatePrimaryAudience = createJwtValidator(betterAuthUrl);
114→  try {
115→    const claims = await validatePrimaryAudience(bearerToken);
116→    if (typeof claims.sub === "string" && claims.sub.length > 0) {
117→      return claims.sub;
118→    }
119→  } catch {
120→    // Try secondary audience below.
121→  }
122→
123→  const authAudience = betterAuthUrl.endsWith("/api/auth")
124→    ? betterAuthUrl
125→    : `${betterAuthUrl}/api/auth`;
126→  if (authAudience === betterAuthUrl) {
127→    return undefined;
128→  }
129→
130→  const validateAuthAudience = createJwtValidator(authAudience);
131→  try {
132→    const claims = await validateAuthAudience(bearerToken);
133→    if (typeof claims.sub === "string" && claims.sub.length > 0) {
134→      return claims.sub;
135→    }
136→  } catch {
137→    return undefined;
138→  }
139→
140→  return undefined;
141→}
142→
143→// ---------------------------------------------------------------------------
144→// Token Rotation (driven port — mutates SurrealDB)
145→// Revoke + issue in a single transaction to avoid a crash window where
146→// no valid token exists.
147→// ---------------------------------------------------------------------------
148→
149→async function rotateProxyToken(
150→  surreal: ServerDependencies["surreal"],
151→  tokenHash: string,
152→  identityId: string,
153→  workspaceId: string,
154→  expiresAt: Date,
155→): Promise<void> {
156→  await surreal.query(
157→    `BEGIN TRANSACTION;
158→     UPDATE proxy_token SET revoked = true WHERE identity = $identity AND workspace = $ws AND revoked = false;
159→     CREATE proxy_token CONTENT {
160→       token_hash: $hash,
161→       workspace: $ws,
162→       identity: $identity,
163→       expires_at: $expires,
164→       created_at: time::now(),
165→       revoked: false,
166→     };
167→     COMMIT TRANSACTION;`,
168→    {
169→      hash: tokenHash,
170→      ws: workspaceRecord(workspaceId),
171→      identity: identityRecord(identityId),
172→      expires: expiresAt,
173→    },
174→  );
175→}
176→
177→// ---------------------------------------------------------------------------
178→// Handler Factory
179→// ---------------------------------------------------------------------------
180→
181→export function createProxyTokenHandler(
182→  deps: ServerDependencies,
183→): (request: Request) => Promise<Response> {
184→  const ttlDays = readProxyTokenTtlDays();
185→
186→  return async (request: Request): Promise<Response> => {
187→    // 1. Parse request
188→    let body: unknown;
189→    try {
190→      body = await request.json();
191→    } catch {
192→      return jsonResponse({ error: "invalid_json" }, 400);
193→    }
194→
195→    const parseResult = parseProxyTokenRequest(
196→      request.headers.get("authorization"),
197→      body,
198→    );
199→
200→    if (!parseResult.ok) {
201→      return jsonResponse({ error: parseResult.error }, parseResult.status);
202→    }
203→
204→    const { workspaceId, bearerToken } = parseResult.value;
205→
206→    // 2. Validate bearer token via Better Auth session
207→    const personId = await validateSession(
208→      deps.auth,
209→      request.headers,
210→      bearerToken,
211→      deps.config.betterAuthUrl,
212→    );
213→    if (!personId) {
214→      return jsonResponse({ error: "invalid_session" }, 401);
215→    }
216→
217→    // 3. Resolve person → identity (scoped to workspace membership)
218→    const identityId = await resolveIdentityForWorkspaceAndPerson(deps.surreal, personId, workspaceId);
219→    if (!identityId) {
220→      return jsonResponse({ error: "workspace_membership_required" }, 403);
221→    }
222→
223→    // 4. Revoke previous tokens + issue new one (atomic)
224→    const rawToken = generateProxyToken();
225→    const tokenHash = hashProxyToken(rawToken);
226→    const expiresAt = computeExpiresAt(ttlDays);
227→
228→    await rotateProxyToken(deps.surreal, tokenHash, identityId, workspaceId, expiresAt);
229→
230→    log.info("proxy.token.issued", "Proxy token issued", {
231→      workspace_id: workspaceId,
232→      identity_id: identityId,
233→      ttl_days: ttlDays,
234→    });
235→
236→    // 5. Return raw token (only time it leaves the server)
237→    return jsonResponse({
238→      proxy_token: rawToken,
239→      expires_at: expiresAt.toISOString(),
240→      workspace_id: workspaceId,
241→    }, 200);
242→  };
243→}
