  81→// ---------------------------------------------------------------------------
  82→// Workspace Validation (cached)
  83→// ---------------------------------------------------------------------------
  84→
  85→type WorkspaceCache = Map<string, { valid: boolean; checkedAt: number }>;
  86→
  87→const WORKSPACE_CACHE_TTL_MS = 60_000; // 1 minute
  88→
  89→async function validateWorkspace(
  90→  surreal: ServerDependencies["surreal"],
  91→  workspaceId: string,
  92→  cache: WorkspaceCache,
  93→): Promise<boolean> {
  94→  const cached = cache.get(workspaceId);
  95→  if (cached && Date.now() - cached.checkedAt < WORKSPACE_CACHE_TTL_MS) {
  96→    return cached.valid;
  97→  }
  98→
  99→  try {
 100→    const results = await surreal.query<[Array<{ id: RecordId }>]>(
 101→      `SELECT id FROM $ws;`,
 102→      { ws: new RecordId("workspace", workspaceId) },
 103→    );
 104→    const valid = (results[0]?.length ?? 0) > 0;
 105→    cache.set(workspaceId, { valid, checkedAt: Date.now() });
 106→    return valid;
 107→  } catch {
 108→    cache.set(workspaceId, { valid: false, checkedAt: Date.now() });
 109→    return false;
 110→  }
