 127→
 128→  for (const name of FORWARDED_HEADERS) {
 129→    const value = request.headers.get(name);
 130→    if (value) headers.set(name, value);
 131→  }
 132→
 133→  if (authMode.mode === "brain" && authMode.serverApiKey) {
 134→    // Brain auth with server-held API key: inject it, do not forward client auth
 135→    headers.set("x-api-key", authMode.serverApiKey);
 136→  } else {
 137→    // Direct auth: forward client's auth headers as-is
 138→    const xApiKey = request.headers.get("x-api-key");
 139→    const authHeader = request.headers.get("authorization");
 140→    if (xApiKey) headers.set("x-api-key", xApiKey);
 141→    if (authHeader) headers.set("authorization", authHeader);
 142→  }
 143→
 144→  return headers;
 145→}
