 147→// ---------------------------------------------------------------------------
 148→// Request Body Parsing
 149→// ---------------------------------------------------------------------------
 150→
 151→type ParsedBody = {
 152→  model?: string;
 153→  stream?: boolean;
 154→  max_tokens?: number;
 155→  metadata?: { user_id?: string };
 156→  system?: string | Array<{ type: string; text: string }>;
 157→  messages?: Array<{ role: string; content: string }>;
 158→};
 159→
 160→type ProxyStage =
 161→  | "parse_request"
 162→  | "resolve_auth"
 163→  | "resolve_identity"
 164→  | "resolve_session"
 165→  | "validate_workspace"
 166→  | "evaluate_policy"
 167→  | "inject_context"
 168→  | "validate_api_key"
 169→  | "forward_upstream"
 170→  | "read_non_streaming_response"
 171→  | "relay_stream"
 172→  | "complete";
 173→
 174→const ERROR_PREVIEW_MAX_CHARS = 240;
 175→
 176→function toErrorPreview(input: string): string {
 177→  const normalized = input.replace(/\s+/g, " ").trim();
 178→  if (normalized.length <= ERROR_PREVIEW_MAX_CHARS) {
 179→    return normalized;
 180→  }
 181→  return `${normalized.slice(0, ERROR_PREVIEW_MAX_CHARS)}...`;
 182→}
 183→
 184→type ProxyErrorPayload = {
 185→  error: {
 186→    type: string;
 187→    message: string;
 188→  };
 189→  stage?: string;
 190→  trace_id?: string;
 191→  upstream_status?: number;
 192→};
 193→
 194→export function buildProxyErrorPayload(
 195→  type: string,
 196→  message: string,
 197→  options?: {
 198→    stage?: string;
 199→    traceId?: string;
 200→    upstreamStatus?: number;
 201→  },
 202→): ProxyErrorPayload {
 203→  return {
 204→    error: { type, message },
 205→    ...(options?.stage ? { stage: options.stage } : {}),
 206→    ...(options?.traceId ? { trace_id: options.traceId } : {}),
 207→    ...(options?.upstreamStatus !== undefined ? { upstream_status: options.upstreamStatus } : {}),
 208→  };
 209→}
 210→
 211→function tryParseRequestBody(body: string): ParsedBody | undefined {
 212→  try {
 213→    return JSON.parse(body) as ParsedBody;
 214→  } catch {
 215→    return undefined;
 216→  }
 217→}
