 227→// ---------------------------------------------------------------------------
 228→// SSE Usage Extraction
 229→// ---------------------------------------------------------------------------
 230→
 231→type StreamContext = {
 232→  model?: string;
 233→  inputTokens: number;
 234→  outputTokens: number;
 235→  cacheCreationTokens: number;
 236→  cacheReadTokens: number;
 237→  stopReason?: string;
 238→};
 239→
 240→function extractSSEUsage(buffer: string, ctx: StreamContext): string {
 241→  const lines = buffer.split("\n");
 242→  const remainder = lines.pop() ?? "";
 243→
 244→  for (const line of lines) {
 245→    if (!line.startsWith("data: ")) continue;
 246→    const data = line.slice(6);
 247→    if (data === "[DONE]") continue;
 248→
 249→    try {
 250→      const event = JSON.parse(data);
 251→
 252→      if (event.type === "message_start" && event.message?.usage) {
 253→        ctx.inputTokens = event.message.usage.input_tokens ?? 0;
 254→        ctx.cacheCreationTokens = event.message.usage.cache_creation_input_tokens ?? 0;
 255→        ctx.cacheReadTokens = event.message.usage.cache_read_input_tokens ?? 0;
 256→        ctx.model = event.message.model ?? ctx.model;
 257→      }
 258→
 259→      if (event.type === "message_delta") {
 260→        if (event.usage?.output_tokens) {
 261→          ctx.outputTokens = event.usage.output_tokens;
 262→        }
 263→        if (event.delta?.stop_reason) {
 264→          ctx.stopReason = event.delta.stop_reason;
 265→        }
 266→      }
 267→    } catch {
 268→      // partial JSON or non-JSON data line — skip
 269→    }
 270→  }
 271→
 272→  return remainder;
 273→}
