 275→// ---------------------------------------------------------------------------
 276→// Non-Streaming Usage Extraction
 277→// ---------------------------------------------------------------------------
 278→
 279→type NonStreamingResponse = {
 280→  model?: string;
 281→  usage?: {
 282→    input_tokens?: number;
 283→    output_tokens?: number;
 284→    cache_creation_input_tokens?: number;
 285→    cache_read_input_tokens?: number;
 286→  };
 287→  stop_reason?: string;
 288→};
 289→
 290→function extractNonStreamingUsage(
 291→  responseBody: string,
 292→  requestModel: string | undefined,
 293→  latencyMs: number,
 294→  identity: { workspaceId?: string; taskId?: string; identityId?: string },
 295→  sessionId?: string,
 296→  policyDecision?: PolicyDecisionLog,
 297→  injectionResult?: InjectionResult,
 298→): TraceData | undefined {
 299→  try {
 300→    const parsed = JSON.parse(responseBody) as NonStreamingResponse;
 301→    if (!parsed.usage) return undefined;
 302→
 303→    const responseContent = extractResponseContent(responseBody);
 304→
 305→    return {
 306→      model: parsed.model ?? requestModel ?? "unknown",
 307→      inputTokens: parsed.usage.input_tokens ?? 0,
 308→      outputTokens: parsed.usage.output_tokens ?? 0,
 309→      cacheCreationTokens: parsed.usage.cache_creation_input_tokens ?? 0,
 310→      cacheReadTokens: parsed.usage.cache_read_input_tokens ?? 0,
 311→      stopReason: parsed.stop_reason,
 312→      latencyMs,
 313→      workspaceId: identity.workspaceId,
 314→      identityId: identity.identityId,
 315→      sessionId,
 316→      taskId: identity.taskId,
 317→      policyDecision,
 318→      ...(injectionResult ? { intelligenceMetadata: buildIntelligenceMetadata(injectionResult) } : {}),
 319→      ...(responseContent ? { responseContent } : {}),
 320→    };
 321→  } catch {
 322→    return undefined;
 323→  }
 324→}
