 326→// ---------------------------------------------------------------------------
 327→// Context Candidate Pool Loader (adapter boundary)
 328→// ---------------------------------------------------------------------------
 329→
 330→const DECISION_WEIGHT = 1.0;
 331→const LEARNING_WEIGHT = 0.8;
 332→const OBSERVATION_WEIGHT = 0.7;
 333→
 334→async function loadCandidatePool(
 335→  surreal: ServerDependencies["surreal"],
 336→  workspaceId: string,
 337→): Promise<CachedCandidatePool> {
 338→  const workspaceRecord = new RecordId("workspace", workspaceId);
 339→
 340→  type DecisionRow = { id: RecordId; summary: string; embedding?: number[] };
 341→  type LearningRow = { id: RecordId; text: string; embedding?: number[] };
 342→  type ObservationRow = { id: RecordId; text: string; embedding?: number[] };
 343→
 344→  // Single round-trip: multiple statements in one .query() call
 345→  const results = await surreal.query<[DecisionRow[], LearningRow[], ObservationRow[]]>(
 346→    `SELECT id, summary, embedding FROM decision WHERE workspace = $ws AND status = 'confirmed' LIMIT 50;
 347→     SELECT id, text, embedding FROM learning WHERE workspace = $ws AND status = 'active' LIMIT 30;
 348→     SELECT id, text, embedding FROM observation WHERE workspace = $ws AND status = 'open' AND severity IN ['conflict', 'warning'] AND source_agent != 'llm-proxy' LIMIT 20;`,
 349→    { ws: workspaceRecord },
 350→  );
 351→
 352→  function toCandidates<T extends { id: RecordId; embedding?: number[] }>(
 353→    rows: T[],
 354→    type: CandidateItem["type"],
 355→    weight: number,
 356→    textFn: (row: T) => string,
 357→  ): CandidateItem[] {
 358→    return rows.map((row) => ({
 359→      id: (row.id as RecordId).id as string,
 360→      type,
 361→      text: textFn(row),
 362→      weight,
 363→      embedding: row.embedding,
 364→    }));
 365→  }
 366→
 367→  const decisions = toCandidates(results[0] ?? [], "decision", DECISION_WEIGHT, (d) => d.summary);
 368→  const learnings = toCandidates(results[1] ?? [], "learning", LEARNING_WEIGHT, (l) => l.text);
 369→  const observations = toCandidates(results[2] ?? [], "observation", OBSERVATION_WEIGHT, (o) => o.text);
 370→
 371→  return {
 372→    decisions,
 373→    learnings,
 374→    observations,
 375→    populatedAt: Date.now(),
 376→  };
 377→}
