 379→// ---------------------------------------------------------------------------
 380→// Embedding Helper (adapter boundary)
 381→// ---------------------------------------------------------------------------
 382→
 383→async function embedUserMessage(
 384→  embeddingModel: ServerDependencies["embeddingModel"],
 385→  embeddingDimension: number,
 386→  text: string,
 387→): Promise<number[] | undefined> {
 388→  try {
 389→    const { embed } = await import("ai");
 390→    const normalized = text.trim();
 391→    if (normalized.length === 0) return undefined;
 392→
 393→    const result = await embed({
 394→      model: embeddingModel,
 395→      value: normalized,
 396→    });
 397→
 398→    if (result.embedding.length !== embeddingDimension) return undefined;
 399→    return result.embedding;
 400→  } catch {
 401→    return undefined;
 402→  }
 403→}
