 405→// ---------------------------------------------------------------------------
 406→// Context Injection Pipeline (orchestrator)
 407→// ---------------------------------------------------------------------------
 408→
 409→type ContextInjectionResult = {
 410→  readonly body: string;
 411→  readonly injectionResult?: InjectionResult;
 412→};
 413→
 414→async function runContextInjection(
 415→  deps: ServerDependencies,
 416→  workspaceId: string,
 417→  parsedBody: ParsedBody,
 418→  originalBody: string,
 419→  contextCache: ContextCache,
 420→  intelligenceConfig: IntelligenceConfig,
 421→  recentChangesSearch?: SearchRecentChanges,
 422→  lastRequestAt?: Date,
 423→): Promise<ContextInjectionResult> {
 424→  if (!intelligenceConfig.contextInjectionEnabled) {
 425→    return { body: originalBody };
 426→  }
 427→
 428→  // 1. Extract last user message for embedding (needed for early-exit check)
 429→  const messages = parsedBody.messages ?? [];
 430→  let lastUserMessage: { role: string; content: string } | undefined;
 431→  for (let i = messages.length - 1; i >= 0; i--) {
 432→    if (messages[i].role === "user") { lastUserMessage = messages[i]; break; }
 433→  }
 434→  if (!lastUserMessage) {
 435→    return { body: originalBody };
 436→  }
 437→
 438→  // 2. Get or populate candidate pool + embed user message in parallel
 439→  let fromCache = false;
 440→  const poolPromise = contextCache.has(workspaceId)
 441→    ? (fromCache = true, Promise.resolve(contextCache.get(workspaceId)!))
 442→    : loadCandidatePool(deps.surreal, workspaceId);
 443→
 444→  const embeddingPromise = embedUserMessage(
 445→    deps.embeddingModel,
 446→    deps.config.embeddingDimension,
 447→    lastUserMessage.content,
 448→  );
 449→
 450→  const [pool, queryEmbedding] = await Promise.all([poolPromise, embeddingPromise]);
 451→
 452→  if (!fromCache) {
 453→    contextCache.set(workspaceId, pool);
 454→  }
 455→
 456→  // 3. Check if pool is empty
 457→  const allCandidates: ContextCandidate[] = [
 458→    ...pool.decisions,
 459→    ...pool.learnings,
 460→    ...pool.observations,
 461→  ];
 462→  if (allCandidates.length === 0) {
 463→    return { body: originalBody };
 464→  }
 465→
 466→  log.info("proxy.context_injection.pool_loaded", "Candidate pool loaded", {
 467→    workspace_id: workspaceId,
 468→    decisions: pool.decisions.length,
 469→    learnings: pool.learnings.length,
 470→    observations: pool.observations.length,
 471→    total: allCandidates.length,
 472→    cached: fromCache,
 473→  });
 474→
 475→  let selectedCandidates;
 476→  if (queryEmbedding) {
 477→    // 5. Rank candidates by weighted cosine similarity
 478→    const ranked = rankCandidates(allCandidates, queryEmbedding);
 479→    // 6. Select within token budget
 480→    selectedCandidates = selectWithinBudget(ranked, intelligenceConfig.contextInjectionTokenBudget);
 481→  } else {
 482→    // No embedding available -- fall back to all candidates within budget
 483→    const ranked = allCandidates.map((c) => ({
 484→      id: c.id,
 485→      type: c.type,
 486→      text: c.text,
 487→      score: c.weight,
 488→    }));
 489→    selectedCandidates = selectWithinBudget(ranked, intelligenceConfig.contextInjectionTokenBudget);
 490→  }
 491→
 492→  if (selectedCandidates.length === 0) {
 493→    return { body: originalBody };
 494→  }
 495→
 496→  // 7. Build XML block
 497→  const brainContextXml = buildBrainContextXml(selectedCandidates);
 498→
 499→  // 8. Inject into system prompt
 500→  const injectionResult = injectBrainContext(parsedBody.system, brainContextXml);
 501→
 502→  // 9. Search and inject recent changes (04-02)
 503→  let enrichedSystem = injectionResult.system;
 504→  if (recentChangesSearch && lastRequestAt && queryEmbedding) {
 505→    try {
 506→      const recentCandidates = await recentChangesSearch(queryEmbedding, workspaceId, lastRequestAt);
 507→      const classified = classifyBySimilarity(recentCandidates);
 508→      const recentChangesXml = buildRecentChangesXml(classified);
 509→      if (recentChangesXml) {
 510→        enrichedSystem = injectRecentChanges(enrichedSystem, recentChangesXml);
 511→      }
 512→    } catch (error) {
 513→      // Fail-open: log and continue without recent changes
 514→      log.warn("proxy.context_injection.recent_changes_failed", "Recent changes search failed", {
 515→        workspace_id: workspaceId,
 516→        error: String(error),
 517→      });
 518→    }
 519→  }
 520→
 521→  // 10. Build modified request body
 522→  const modifiedBody = {
 523→    ...parsedBody,
 524→    system: enrichedSystem,
 525→  };
 526→
 527→  return {
 528→    body: JSON.stringify(modifiedBody),
 529→    injectionResult,
 530→  };
 531→}
