 533→// ---------------------------------------------------------------------------
 534→// Intelligence Metadata Builder (pure)
 535→// ---------------------------------------------------------------------------
 536→
 537→function buildIntelligenceMetadata(injectionResult: InjectionResult) {
 538→  return {
 539→    brain_context_injected: injectionResult.injected,
 540→    brain_context_decisions: injectionResult.decisionsCount,
 541→    brain_context_learnings: injectionResult.learningsCount,
 542→    brain_context_observations: injectionResult.observationsCount,
 543→    brain_context_tokens_est: injectionResult.tokensEstimated,
 544→  };
