 584→// ---------------------------------------------------------------------------
 585→
 586→function buildPolicyDenialResponse(
 587→  result: Exclude<ProxyPolicyResult, { decision: "allow" }>,
 588→): Response {
 589→  if (result.decision === "deny_rate_limit") {
 590→    return new Response(JSON.stringify(result.body), {
 591→      status: result.status,
 592→      headers: {
 593→        "Content-Type": "application/json",
 594→        "Retry-After": String(result.retryAfterSeconds),
 595→        "Access-Control-Allow-Origin": "*",
 596→      },
 597→    });
 598→  }
 599→  return jsonResponse(result.body, result.status);
 600→}
