 633→// ---------------------------------------------------------------------------
 634→// Handler Factory
 635→// ---------------------------------------------------------------------------
 636→
 637→export function createAnthropicProxyHandler(
 638→  deps: ServerDependencies,
 639→): (request: Request) => Promise<Response> {
 640→  const workspaceCache: WorkspaceCache = new Map();
 641→  const rateLimiterState: RateLimiterState = createRateLimiterState();
 642→  const spendCache: SpendCache = new Map();
 643→  const noPolicyWarnedWorkspaces = new Set<string>();
 644→  const contextCache: ContextCache = createContextCache(300); // default TTL, overridden per-workspace
 645→
 646→  // Proxy auth: per-handler cache + DB lookup function (not module-level singletons)
 647→  const proxyTokenCache: TokenCache = createTokenCache();
 648→  const lookupProxyToken: LookupProxyToken = createLookupProxyToken(deps.surreal);
 649→
 650→  // Recent changes adapter for vector search (04-02)
 651→  const searchRecentChanges: SearchRecentChanges = createSearchRecentChanges(deps.surreal);
 652→
 653→  // Periodic pruning of stale rate limiter entries to prevent unbounded Map growth.
 654→  // unref() ensures this interval does not keep the process alive on shutdown.
 655→  const pruneInterval = setInterval(
 656→    () => {
 657→      pruneStaleEntries(rateLimiterState, Date.now());
 658→      const nowMs = Date.now();
 659→      for (const [key, entry] of proxyTokenCache) {
 660→        if (nowMs >= entry.expiresAt) proxyTokenCache.delete(key);
 661→      }
 662→    },
 663→    5 * 60 * 1000,
 664→  );
 665→  pruneInterval.unref();
 666→
 667→  const anthropicApiUrl = deps.config.anthropicApiUrl;
 668→
 669→  return async (request: Request): Promise<Response> => {
 670→    const startedAt = performance.now();
 671→    const url = new URL(request.url);
 672→    const upstreamPath = url.pathname.replace(/^\/proxy\/llm\/anthropic/, "");
 673→    const upstreamUrl = `${anthropicApiUrl}${upstreamPath}`;
 674→    const isCountTokens = isCountTokensRequest(url.pathname);
 675→    const span = trace.getActiveSpan();
 676→    const traceId = span?.spanContext().traceId;
 677→    const requestMode = request.headers.get("X-Brain-Auth") ? "brain" : "direct";
 678→
 679→    const setSpanAttributes = (attributes: Record<string, string | number | boolean | undefined>) => {
 680→      if (!span) return;
 681→      for (const [key, value] of Object.entries(attributes)) {
 682→        if (value !== undefined) {
 683→          span.setAttribute(key, value);
 684→        }
 685→      }
 686→    };
 687→
 688→    let currentStage: ProxyStage = "parse_request";
 689→    const setStage = (stage: ProxyStage) => {
 690→      currentStage = stage;
 691→      setSpanAttributes({ "proxy.stage": stage });
 692→    };
 693→    setStage("parse_request");
 694→
 695→    setSpanAttributes({
 696→      "proxy.path": upstreamPath,
 697→      "proxy.upstream_url": upstreamUrl,
 698→      "proxy.is_count_tokens": isCountTokens,
 699→      "proxy.request_mode": requestMode,
 700→    });
 701→
 702→    // --- Step 1: Parse request body (malformed body forwarded as-is) ---
 703→    let body: string;
 704→    let parsed: ParsedBody | undefined;
 705→    let isStreaming = false;
 706→    let identitySignals:
 707→      | ReturnType<typeof resolveIdentity>
 708→      | undefined;
 709→
 710→    try {
 711→      body = await request.text();
 712→      parsed = tryParseRequestBody(body);
 713→      isStreaming = parsed?.stream === true;
 714→      setSpanAttributes({
 715→        "proxy.request_body_parsed": parsed !== undefined,
 716→        "proxy.request_body_bytes": body.length,
 717→        "proxy.request_model": parsed?.model,
 718→        "proxy.is_streaming": isStreaming,
 719→      });
 720→
 721→      // --- Step 1.5: Brain auth resolution (dual-mode) ---
 722→      setStage("resolve_auth");
 723→      let brainAuthResult: ProxyAuthResult | undefined;
 724→      let authMode: AuthMode = { mode: "direct" };
 725→
 726→      try {
 727→        brainAuthResult = await resolveProxyAuth(
 728→          request.headers,
 729→          lookupProxyToken,
 730→          proxyTokenCache,
 731→        );
 732→      } catch (error) {
 733→        if (error instanceof ProxyAuthError) {
 734→          setSpanAttributes({
 735→            "proxy.error.type": "authentication_error",
 736→            "proxy.error.stage": currentStage,
 737→          });
 738→          log.warn("proxy.anthropic.auth_failed", "Brain auth failed", {
 739→            stage: currentStage,
 740→            error: error.message,
 741→          });
 742→          return jsonResponse(
 743→            buildProxyErrorPayload(
 744→              "authentication_error",
 745→              error.message,
 746→              { stage: currentStage, traceId },
 747→            ),
 748→            401,
 749→          );
 750→        }
 751→        throw error;
 752→      }
 753→
 754→      if (brainAuthResult) {
 755→        // Brain auth mode: use server API key if available, otherwise forward client auth headers
 756→        authMode = { mode: "brain", serverApiKey: deps.config.anthropicApiKey };
 757→      }
 758→      setSpanAttributes({ "proxy.auth_mode": authMode.mode });
 759→
 760→      // --- Step 2: Identity resolution ---
 761→      setStage("resolve_identity");
 762→      // In Brain auth mode, workspace comes from the token (not from headers)
 763→      identitySignals = resolveIdentity({
 764→        metadataUserId: parsed?.metadata?.user_id,
 765→        workspaceHeader: brainAuthResult?.workspaceId ?? (request.headers.get("X-Brain-Workspace") ?? undefined),
 766→        taskHeader: request.headers.get("X-Brain-Task") ?? undefined,
 767→        agentTypeHeader: request.headers.get("X-Brain-Agent-Type") ?? undefined,
 768→        sessionHeader: request.headers.get("X-Brain-Session") ?? undefined,
 769→        proxyTokenIdentityId: brainAuthResult?.identityId,
 770→        userAgent: request.headers.get("User-Agent") ?? undefined,
 771→      });
 772→      setSpanAttributes({
 773→        "proxy.workspace_id": identitySignals.workspaceId,
 774→        "proxy.task_id": identitySignals.taskId,
 775→        "proxy.agent_type": identitySignals.agentType,
 776→        "proxy.session_header": identitySignals.sessionHeaderId,
 777→      });
 778→
 779→      // --- Step 3: Session ID resolution ---
 780→      setStage("resolve_session");
 781→      // resolveSessionId returns either the header PK or the external Claude Code
 782→      // session UUID. Resolve to the actual agent_session PK via DB lookup.
 783→      const rawSessionId = resolveSessionId(identitySignals);
 784→      let effectiveSessionId = rawSessionId
 785→        ? await resolveAgentSessionId(deps.surreal, rawSessionId)
 786→        : undefined;
 787→      setSpanAttributes({
