721→      // --- Step 1.5: Brain auth resolution (dual-mode) ---
722→      setStage("resolve_auth");
723→      let brainAuthResult: ProxyAuthResult | undefined;
724→      let authMode: AuthMode = { mode: "direct" };
725→
726→      try {
727→        brainAuthResult = await resolveProxyAuth(
728→          request.headers,
729→          lookupProxyToken,
730→          proxyTokenCache,
731→        );
732→      } catch (error) {
733→        if (error instanceof ProxyAuthError) {
734→          setSpanAttributes({
735→            "proxy.error.type": "authentication_error",
736→            "proxy.error.stage": currentStage,
737→          });
738→          log.warn("proxy.anthropic.auth_failed", "Brain auth failed", {
739→            stage: currentStage,
740→            error: error.message,
741→          });
742→          return jsonResponse(
743→            buildProxyErrorPayload(
744→              "authentication_error",
745→              error.message,
746→              { stage: currentStage, traceId },
747→            ),
748→            401,
749→          );
750→        }
751→        throw error;
752→      }
753→
754→      if (brainAuthResult) {
755→        // Brain auth mode: use server API key if available, otherwise forward client auth headers
756→        authMode = { mode: "brain", serverApiKey: deps.config.anthropicApiKey };
757→      }
758→      setSpanAttributes({ "proxy.auth_mode": authMode.mode });
759→
760→      // --- Step 2: Identity resolution ---
761→      setStage("resolve_identity");
762→      // In Brain auth mode, workspace comes from the token (not from headers)
763→      identitySignals = resolveIdentity({
764→        metadataUserId: parsed?.metadata?.user_id,
765→        workspaceHeader: brainAuthResult?.workspaceId ?? (request.headers.get("X-Brain-Workspace") ?? undefined),
766→        taskHeader: request.headers.get("X-Brain-Task") ?? undefined,
767→        agentTypeHeader: request.headers.get("X-Brain-Agent-Type") ?? undefined,
768→        sessionHeader: request.headers.get("X-Brain-Session") ?? undefined,
769→        proxyTokenIdentityId: brainAuthResult?.identityId,
770→        userAgent: request.headers.get("User-Agent") ?? undefined,
771→      });
772→      setSpanAttributes({
773→        "proxy.workspace_id": identitySignals.workspaceId,
774→        "proxy.task_id": identitySignals.taskId,
775→        "proxy.agent_type": identitySignals.agentType,
776→        "proxy.session_header": identitySignals.sessionHeaderId,
777→      });
778→
779→      // --- Step 3: Session ID resolution ---
780→      setStage("resolve_session");
781→      // resolveSessionId returns either the header PK or the external Claude Code
782→      // session UUID. Resolve to the actual agent_session PK via DB lookup.
783→      const rawSessionId = resolveSessionId(identitySignals);
784→      let effectiveSessionId = rawSessionId
785→        ? await resolveAgentSessionId(deps.surreal, rawSessionId)
786→        : undefined;
787→      setSpanAttributes({
788→        "proxy.session_id.raw": rawSessionId,
789→        "proxy.session_id.effective": effectiveSessionId,
790→      });
791→
792→      // --- Step 3.5: Session hash fallback ---
793→      // When no explicit session signal exists, derive a deterministic session
794→      // identity from request content (system_prompt + first_user_message).
795→      if (!effectiveSessionId && identitySignals.workspaceId && parsed) {
796→        const sessionHashInput: SessionHashInput = {
797→          systemPrompt: typeof parsed.system === "string" ? parsed.system : undefined,
798→          systemPromptBlocks: Array.isArray(parsed.system) ? parsed.system : undefined,
799→          messages: parsed.messages ?? [],
800→        };
801→        const sessionHash = resolveSessionHash(sessionHashInput);
802→
803→        if (sessionHash) {
804→          try {
805→            const upsertedSessionId = await upsertProxySession(
806→              {
807→                sessionId: sessionHash.sessionId,
808→                workspaceId: identitySignals.workspaceId,
809→                agent: resolveAgentName(identitySignals),
810→              },
811→              { surreal: deps.surreal },
812→            );
813→            if (upsertedSessionId) {
814→              effectiveSessionId = upsertedSessionId;
815→              setSpanAttributes({ "proxy.session_id.effective": effectiveSessionId });
816→            }
