  1→/**
  2→ * Acceptance Tests: Policy Enforcement at Proxy Boundary (Step 02-01)
  3→ *
  4→ * Driving port: POST /proxy/llm/anthropic/v1/messages
  5→ *
  6→ * Validates that the proxy evaluates model access policies, budget limits,
  7→ * and rate limits before forwarding requests. Clear error responses for
  8→ * violations. No policies defaults to permissive with warning observation.
  9→ * Policy decisions logged for audit trail.
 10→ */
 11→import { describe, expect, it, beforeAll } from "bun:test";
 12→import { RecordId } from "surrealdb";
 13→import {
 14→  setupAcceptanceSuite,
 15→  sendProxyRequest,
 16→  createProxyTestWorkspace,
 17→  seedLlmTrace,
 18→  getObservationsForWorkspace,
 19→  TEST_PROXY_MODEL,
 20→} from "./llm-proxy-test-kit";
 21→
 22→const getRuntime = setupAcceptanceSuite("llm_proxy_policy");
 23→
 24→// ---------------------------------------------------------------------------
 25→// Helpers: Policy setup that works with SCHEMAFULL policy table
 26→// ---------------------------------------------------------------------------
 27→
 28→async function createProxyModelPolicy(
 29→  surreal: import("surrealdb").Surreal,
 30→  workspaceId: string,
 31→  options: {
 32→    policyId: string;
 33→    agentType: string;
 34→    allowedModels: string[];
 35→    identityId?: string;
 36→  },
 37→): Promise<string> {
 38→  const policyRecord = new RecordId("policy", options.policyId);
 39→  const workspaceRecord = new RecordId("workspace", workspaceId);
 40→  const identityId = options.identityId ?? `identity-${crypto.randomUUID()}`;
 41→  const identityRecord = new RecordId("identity", identityId);
 42→
 43→  // Ensure identity exists
 44→  await surreal.query(`CREATE $identity CONTENT $content;`, {
 45→    identity: identityRecord,
 46→    content: { created_at: new Date() },
 47→  }).catch(() => undefined); // ignore if exists
 48→
 49→  await surreal.query(`CREATE $policy CONTENT $content;`, {
 50→    policy: policyRecord,
 51→    content: {
 52→      title: `Model Access: ${options.agentType}`,
 53→      description: `Controls which models ${options.agentType} can use`,
 54→      status: "active",
 55→      version: 1,
 56→      selector: { agent_role: options.agentType },
 57→      workspace: workspaceRecord,
 58→      created_by: identityRecord,
 59→      rules: [
 60→        {
 61→          id: "model_access",
 62→          condition: {
 63→            field: "model",
 64→            operator: "not_in",
 65→            value: options.allowedModels,
 66→          },
 67→          effect: "deny",
 68→          priority: 100,
 69→        },
 70→      ],
 71→      human_veto_required: false,
 72→      created_at: new Date(),
 73→    },
 74→  });
 75→
 76→  // Create protects edge so loadActivePolicies can find it
 77→  await surreal.query(
 78→    `RELATE $policy->protects->$workspace SET created_at = time::now();`,
 79→    { policy: policyRecord, workspace: workspaceRecord },
 80→  );
 81→
 82→  return options.policyId;
 83→}
 84→
 85→async function setWorkspaceDailyBudget(
 86→  surreal: import("surrealdb").Surreal,
 87→  workspaceId: string,
 88→  dailyBudgetUsd: number,
 89→): Promise<void> {
 90→  const workspaceRecord = new RecordId("workspace", workspaceId);
 91→  await surreal.query(
 92→    `UPDATE $workspace SET daily_budget_usd = $budget;`,
 93→    { workspace: workspaceRecord, budget: dailyBudgetUsd },
 94→  );
 95→}
