 97→// ---------------------------------------------------------------------------
 98→// Scenario 1: Model access violation returns 403
 99→// ---------------------------------------------------------------------------
100→describe("Unauthorized model request blocked with policy reference", () => {
101→  it("returns 403 with policy violation details when model is not allowed", async () => {
102→    const { baseUrl, surreal } = getRuntime();
103→
104→    const workspaceId = `ws-pol-deny-${crypto.randomUUID()}`;
105→    await createProxyTestWorkspace(surreal, workspaceId);
106→
107→    // Given: workspace policy allows observer to use only haiku
108→    const policyId = `pol-restrict-${crypto.randomUUID()}`;
109→    await createProxyModelPolicy(surreal, workspaceId, {
110→      policyId,
111→      agentType: "observer",
112→      allowedModels: ["claude-3-5-haiku-20241022"],
113→    });
114→
115→    // When: observer requests opus (not in allowed list)
