136→// ---------------------------------------------------------------------------
137→// Scenario 2: Budget exceeded returns 429
138→// ---------------------------------------------------------------------------
139→describe("Budget exceeded request blocked with spend details", () => {
140→  it("returns 429 with current spend and daily limit when budget exhausted", async () => {
141→    const { baseUrl, surreal } = getRuntime();
142→
143→    const workspaceId = `ws-budget-${crypto.randomUUID()}`;
144→    await createProxyTestWorkspace(surreal, workspaceId);
