149→      await seedLlmTrace(surreal, `trace-bud-${crypto.randomUUID()}`, {
150→        model: TEST_PROXY_MODEL,
151→        input_tokens: 10000,
152→        output_tokens: 2000,
153→        cost_usd: 3.50,
154→        latency_ms: 1000,
155→        workspaceId,
156→      });
157→    }
158→
159→    // When: agent makes another LLM request
160→    const response = await sendProxyRequest(baseUrl, {
161→      model: TEST_PROXY_MODEL,
162→      stream: false,
163→      maxTokens: 10,
164→      messages: [{ role: "user", content: "hi" }],
165→      apiKey: "sk-test-unused",
166→      workspaceHeader: workspaceId,
167→      agentTypeHeader: "coding-agent",
168→    });
169→
170→    // Then: 429 with budget details
171→    expect(response.status).toBe(429);
172→
173→    const body = await response.json() as Record<string, unknown>;
174→    expect(body.error).toBe("budget_exceeded");
175→    expect(body.current_spend_usd).toBeDefined();
176→    expect(body.daily_limit_usd).toBe(10.0);
