181→// ---------------------------------------------------------------------------
182→// Scenario 3: Rate limit exceeded returns 429 with Retry-After
183→// ---------------------------------------------------------------------------
184→describe("Rate limited request blocked with retry guidance", () => {
185→  it("returns 429 with Retry-After header after exceeding rate limit", async () => {
186→    const { baseUrl, surreal } = getRuntime();
187→
188→    const workspaceId = `ws-rate-${crypto.randomUUID()}`;
189→    await createProxyTestWorkspace(surreal, workspaceId);
190→
191→    // When: sending requests rapidly to exceed rate limit
192→    // The rate limiter should be configured with a low limit for testability.
193→    // We send requests in rapid succession and expect at least one to be rate-limited.
194→    const responses: Response[] = [];
195→    // Send 65 requests rapidly (default limit is 60/min per workspace)
196→    const promises = Array.from({ length: 65 }, () =>
197→      sendProxyRequest(baseUrl, {
198→        model: TEST_PROXY_MODEL,
199→        stream: false,
200→        maxTokens: 10,
201→        messages: [{ role: "user", content: "hi" }],
202→        apiKey: "sk-test-unused",
203→        workspaceHeader: workspaceId,
204→        agentTypeHeader: "coding-agent",
205→      }),
206→    );
207→
208→    const results = await Promise.all(promises);
209→    const rateLimited = results.filter((r) => r.status === 429);
210→
211→    // Then: at least one request is rate-limited
212→    expect(rateLimited.length).toBeGreaterThan(0);
213→
214→    const body = await rateLimited[0].json() as Record<string, unknown>;
215→    expect(body.error).toBe("rate_limit_exceeded");
216→    expect(body.rate_limit_per_minute).toBeDefined();
217→
218→    // And: Retry-After header is present
