226→// ---------------------------------------------------------------------------
227→describe("No policies defaults to permissive with warning", () => {
228→  it("forwards request when no policies exist and creates warning observation", async () => {
229→    const { baseUrl, surreal } = getRuntime();
230→
231→    const workspaceId = `ws-nopol-${crypto.randomUUID()}`;
232→    await createProxyTestWorkspace(surreal, workspaceId);
233→
234→    // Given: workspace has NO model access policies
235→
236→    // When: agent requests any model
