 61→): RateLimitResult {
 62→  const cutoff = now - state.windowMs;
 63→
 64→  let entry = state.windows.get(workspaceId);
 65→  if (!entry) {
 66→    entry = { timestamps: [] };
 67→    state.windows.set(workspaceId, entry);
 68→  }
 69→
 70→  // Prune expired timestamps
 71→  entry.timestamps = entry.timestamps.filter((t) => t > cutoff);
 72→
 73→  if (entry.timestamps.length >= state.limitPerMinute) {
 74→    // Find earliest timestamp in window to compute retry-after
 75→    const earliest = entry.timestamps[0];
 76→    const resetTimeMs = earliest + state.windowMs;
 77→    const retryAfterSeconds = Math.ceil((resetTimeMs - now) / 1000);
 78→
 79→    return {
